using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares the built-in Math.Atan / MathF.Atan against the FastAtan approximation generated by
/// AtanFunctionOptimizer and two improved scalar alternatives.
///
/// Two precision groups are benchmarked independently:
///   Float  – MathF.Atan  vs float.AtanPi  vs CurrentFastAtan(float)  vs FastAtanV2(float)  vs FastAtanV3(float)
///   Double – Math.Atan   vs double.AtanPi vs CurrentFastAtan(double) vs FastAtanV2(double) vs FastAtanV3(double)
///
/// Current FastAtan issues:
///   Uses a Padé [2/2] approximant z*(15+4z²)/(z⁴+9z²+15) which matches Taylor only to O(z³).
///   Range reduction for |x|>1 uses ReciprocalEstimate (≈12-bit accuracy for float), compounding
///   the error. Three inf/nan guards add branch pressure. Max error ≈ 2.5e-2 rad.
///
/// Key design decisions for V2/V3:
///   V2 (float + double): Branchless range reduction + 5-term A&amp;S §4.4.43 minimax polynomial.
///     If |x| > 1, use exact a = 1/|x| and then atan(x) = sign(x)*(π/2 − atan(a)).
///     atan(a) ≈ a*(c₁ + u*(c₃ + u*(c₅ + u*(c₇ + u*c₉)))) on a ∈ [0, 1], u = a².
///     4 FMAs + 1 mul; no rational division in the core.
///     Max absolute error ≈ 1.1e-5 rad — ~2000× more accurate than current Padé.
///   V3 (float): Steinmetz 2-term: atan(a) ≈ a*(π/4 + 0.273*(1−a)) on reduced a ∈ [0, 1].
///     1 FMA + 1 mul in the polynomial core; fastest scalar variant.
///     Max absolute error ≈ 5e-3 rad.
///   V3 (double): Half-angle t = a/(1+√(1+a²)) maps a∈[0,1] → t∈[0,tan(π/8)], then
///     8-term Horner Taylor series on the reduced interval.
///     Truncation error ≤ t^17/17 doubled ≈ 4e-8 rad; one sqrt, no polynomial division.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*AtanBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class AtanBenchmark
{
	// 1 024 values distributed over [-4, 4].
	// Includes values both inside and outside [-1, 1] so the reciprocal branch is exercised.
	private const int N = 1_024;
	private float[]  _floatData  = null!;
	private double[] _doubleData = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatData  = new float[N];
		_doubleData = new double[N];

		for (var i = 0; i < N; i++)
		{
			var v = rng.NextDouble() * 8.0 - 4.0; // uniform in [-4, 4]
			_floatData[i]  = (float)v;
			_doubleData[i] = v;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	/// <summary>Built-in MathF.Atan — hardware-accurate, full-precision float result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAtan_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += MathF.Atan(v);
		return sum;
	}

	/// <summary>
	/// Built-in float.AtanPi — computes atan(x)/π (IEEE 754-2019 §9.2), hardware-assisted.
	/// Included for reference: same operation but result normalised to turns.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAtanPi_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += float.AtanPi(v);
		return sum;
	}

	/// <summary>
	/// Current FastAtan(float) from AtanFunctionOptimizer — branched Padé [2/2] rational
	/// approximant with ReciprocalEstimate for |x|>1 range reduction.
	/// Max absolute error ≈ 2.5e-2 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float CurrentFastAtan_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += CurrentFastAtanFloat(v);
		return sum;
	}

	/// <summary>
	/// FastAtanV2(float) — branchless range reduction + 5-term A&amp;S §4.4.43 minimax polynomial.
	/// For |x|>1 an exact reciprocal (1/absX) replaces the lossy ReciprocalEstimate.
	/// atan(a) ≈ a*(c₁ + u*(c₃ + u*(c₅ + u*(c₇ + u*c₉)))) with u = a².
	/// 4 FMAs + 1 mul; no rational division in core.
	/// Max absolute error ≈ 1.1e-5 rad — ~2000× better than the current Padé.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtanV2_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FastAtanFloatV2(v);
		return sum;
	}

	/// <summary>
	/// FastAtanV3(float) — Steinmetz 2-term: atan(a) ≈ a*(π/4 + 0.273*(1−a)) on a ∈ [0, 1].
	/// Equivalent to FMA(−0.273, a, π/4+0.273) * a; 1 FMA + 1 mul — fastest scalar variant.
	/// Max absolute error ≈ 5e-3 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtanV3_Float()
	{
		var sum = 0f;
		foreach (var v in _floatData)
			sum += FastAtanFloatV3(v);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	/// <summary>Built-in Math.Atan — hardware-accurate, full-precision double result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAtan_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += Math.Atan(v);
		return sum;
	}

	/// <summary>
	/// Built-in double.AtanPi — computes atan(x)/π (IEEE 754-2019 §9.2), hardware-assisted.
	/// Included for reference: same operation normalised to turns.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAtanPi_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += double.AtanPi(v);
		return sum;
	}

	/// <summary>
	/// Current FastAtan(double) from AtanFunctionOptimizer — same branched Padé approximant
	/// as the float version, but using Double.ReciprocalEstimate.
	/// Max absolute error ≈ 2.5e-2 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double CurrentFastAtan_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += CurrentFastAtanDouble(v);
		return sum;
	}

	/// <summary>
	/// FastAtanV2(double) — same branchless range reduction + A&amp;S §4.4.43 minimax polynomial
	/// as V2 float, evaluated in double arithmetic.
	/// Max absolute error ≈ 1.1e-5 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtanV2_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAtanDoubleV2(v);
		return sum;
	}

	/// <summary>
	/// FastAtanV3(double) — half-angle reduction t = a/(1+√(1+a²)) maps a∈[0,1] →
	/// t∈[0,tan(π/8)] then 8-term Horner Taylor series on the reduced interval.
	/// Identity: atan(a) = 2·atan(t). One sqrt per call; max absolute error ≈ 4e-8 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtanV3_Double()
	{
		var sum = 0.0;
		foreach (var v in _doubleData)
			sum += FastAtanDoubleV3(v);
		return sum;
	}

	// ── current implementations (exact mirror of AtanFunctionOptimizer generated code) ──

	private static float CurrentFastAtanFloat(float x)
	{
		if (Single.IsNaN(x)) return Single.NaN;
		if (Single.IsPositiveInfinity(x)) return Single.Pi / 2;
		if (Single.IsNegativeInfinity(x)) return -Single.Pi / 2;

		var absX = Single.Abs(x);
		var sign = Single.Sign(x);

		var useReciprocal = absX > 1.0f;
		var z = useReciprocal ? Single.ReciprocalEstimate(absX) : absX;

		var z2 = z * z;
		var z4 = z2 * z2;
		var numerator   = Single.FusedMultiplyAdd(4.0f, z2, 15.0f);
		numerator      *= z;
		var denominator = Single.FusedMultiplyAdd(9.0f, z2, 15.0f);
		denominator     = z4 + denominator;
		var result      = numerator / denominator;

		if (useReciprocal)
			result = Single.Pi / 2 - result;

		return sign * result;
	}

	private static double CurrentFastAtanDouble(double x)
	{
		if (Double.IsNaN(x)) return Double.NaN;
		if (Double.IsPositiveInfinity(x)) return Double.Pi / 2;
		if (Double.IsNegativeInfinity(x)) return -Double.Pi / 2;

		var absX = Double.Abs(x);
		var sign = Double.Sign(x);

		var useReciprocal = absX > 1.0;
		var z = useReciprocal ? Double.ReciprocalEstimate(absX) : absX;

		var z2 = z * z;
		var z4 = z2 * z2;
		var numerator   = Double.FusedMultiplyAdd(4.0, z2, 15.0);
		numerator      *= z;
		var denominator = Double.FusedMultiplyAdd(9.0, z2, 15.0);
		denominator     = z4 + denominator;
		var result      = numerator / denominator;

		if (useReciprocal)
			result = Double.Pi / 2 - result;

		return sign * result;
	}

	// ── improved implementations ────────────────────────────────────────────

	/// <summary>
	/// Branchless range reduction (exact 1/absX) + A&amp;S §4.4.43 5-term minimax polynomial.
	/// For |x| > 1: a = 1/|x| ∈ [0,1], atan(x) = sign(x)*(π/2 − atan(a)).
	/// For |x| ≤ 1: a = |x|, atan(x) = sign(x)*atan(|x|).
	/// Polynomial: atan(a)/a = c₁ + u*(c₃ + u*(c₅ + u*(c₇ + u*c₉))), u = a².
	/// Quadrant adjustments compile to conditional-move instructions on x86/ARM64.
	/// </summary>
	private static float FastAtanFloatV2(float x)
	{
		if (float.IsNaN(x)) return float.NaN;
		var absX = float.Abs(x);
		var swap = absX > 1.0f;
		var a = swap ? 1.0f / absX : absX; // exact reciprocal, no ReciprocalEstimate
		var u = a * a;

		// A&S §4.4.43 minimax coefficients: max |ε| ≤ 1.1e-5 rad
		var p = float.FusedMultiplyAdd(u,  0.0208351f, -0.0851330f);
		p      = float.FusedMultiplyAdd(u, p,           0.1801410f);
		p      = float.FusedMultiplyAdd(u, p,          -0.3302995f);
		p      = float.FusedMultiplyAdd(u, p,           0.9998660f);
		p     *= a;

		// Restore atan(x) from reduced a ∈ [0,1]
		p = swap ? 1.5707963268f - p : p; // atan(x) = π/2 − atan(1/|x|) when |x|>1
		return float.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Steinmetz 2-term approximation: atan(a) ≈ a*(π/4 + 0.273*(1−a)) on reduced a ∈ [0, 1].
	/// Rewritten as FMA(−0.273, a, π/4+0.273) * a — a single FMA + one multiply.
	/// Fastest scalar Atan variant; atan(0)=0 and atan(1)=π/4 hold exactly; 0.273 minimises max error.
	/// </summary>
	private static float FastAtanFloatV3(float x)
	{
		if (float.IsNaN(x)) return float.NaN;
		var absX = float.Abs(x);
		var swap = absX > 1.0f;
		var a = swap ? 1.0f / absX : absX;

		// π/4 + 0.273 = 0.7853981 + 0.273 = 1.0583981
		var p = float.FusedMultiplyAdd(-0.273f, a, 1.0583981f) * a;

		p = swap ? 1.5707963268f - p : p;
		return float.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Same branchless range reduction + A&amp;S §4.4.43 polynomial in double precision.
	/// Exact 1/absX reciprocal; same coefficient set as V2 float.
	/// Max absolute error ≈ 1.1e-5 rad.
	/// </summary>
	private static double FastAtanDoubleV2(double x)
	{
		if (double.IsNaN(x)) return double.NaN;
		var absX = double.Abs(x);
		var swap = absX > 1.0;
		var a = swap ? 1.0 / absX : absX;
		var u = a * a;

		// A&S §4.4.43 minimax coefficients in double arithmetic
		var p = double.FusedMultiplyAdd(u,  0.0208351, -0.0851330);
		p      = double.FusedMultiplyAdd(u, p,          0.1801410);
		p      = double.FusedMultiplyAdd(u, p,         -0.3302995);
		p      = double.FusedMultiplyAdd(u, p,          0.9998660);
		p     *= a;

		p = swap ? Math.PI / 2.0 - p : p;
		return double.IsNegative(x) ? -p : p;
	}

	/// <summary>
	/// Half-angle reduction: t = a/(1+√(1+a²)) maps a ∈ [0,1] to t ∈ [0,tan(π/8)] ≈ [0, 0.4142].
	/// Identity: atan(a) = 2·atan(t).  On the reduced interval, an 8-term Horner Taylor series
	/// atan(t)/t = Σ (−u)^n/(2n+1) converges with truncation error ≤ t^17/17 ≈ 1.8e-8.
	/// After doubling: max absolute error ≈ 4e-8 rad.  One sqrt; no polynomial division.
	/// </summary>
	private static double FastAtanDoubleV3(double x)
	{
		if (double.IsNaN(x)) return double.NaN;
		var absX = double.Abs(x);
		var swap = absX > 1.0;
		var a = swap ? 1.0 / absX : absX;

		// Half-angle reduction: atan(a) = 2·atan(t),  t = a/(1+√(1+a²))
		var t = a / (1.0 + Math.Sqrt(1.0 + a * a));
		var u = t * t;

		// 8-term Horner Taylor series: atan(t)/t = 1 − u/3 + u²/5 − … + u⁷/15 − u⁸/... 
		var p = double.FusedMultiplyAdd(u, -1.0 / 15.0,  1.0 / 13.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 / 11.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0 /  9.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 /  7.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0 /  5.0);
		p      = double.FusedMultiplyAdd(u, p,           -1.0 /  3.0);
		p      = double.FusedMultiplyAdd(u, p,            1.0);
		p = 2.0 * t * p; // atan(a) = 2·atan(t)

		p = swap ? Math.PI / 2.0 - p : p;
		return double.IsNegative(x) ? -p : p;
	}
}

